import{_ as e,a as t,b as o,c as i,d as r,e as d,f as n}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as l,c as p,a2 as c}from"./chunks/framework.DnrXFDHb.js";const j=JSON.parse('{"title":"Dodawanie kanału Discord","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/discord.md","filePath":"pl-PL/upload/discord.md","lastUpdated":1781962217000}'),k={name:"pl-PL/upload/discord.md"};function w(h,a,z,y,u,b){return l(),p("div",null,[...a[0]||(a[0]=[c('<h1 id="dodawanie-kanału-discord" tabindex="-1">Dodawanie kanału Discord <a class="header-anchor" href="#dodawanie-kanału-discord" aria-label="Permalink to &quot;Dodawanie kanału Discord&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Cel</th></tr></thead><tbody><tr><td>Konto Discord</td><td>Do utworzenia serwera, kanału i aplikacji deweloperskiej.</td></tr><tr><td>Serwer Discord</td><td>Bot musi dołączyć do serwera, zanim uzyska dostęp do kanału.</td></tr><tr><td>Kanał tekstowy</td><td>Obrazy i pliki będą wysyłane do tego kanału.</td></tr><tr><td>Discord Developer Portal</td><td>Do utworzenia aplikacji, bota i pobrania <code>Bot Token</code>.</td></tr></tbody></table><h2 id="gdzie-dodac-kanał" tabindex="-1">Gdzie dodać kanał <a class="header-anchor" href="#gdzie-dodac-kanał" aria-label="Permalink to &quot;Gdzie dodać kanał&quot;">​</a></h2><ol><li>Otwórz Ustawienia systemowe.</li><li>Przejdź do Ustawień przesyłania.</li><li>Kliknij Dodaj kanał w prawym górnym rogu.</li><li>Wybierz <code>Discord</code>.</li></ol><h2 id="opis-pol" tabindex="-1">Opis pól <a class="header-anchor" href="#opis-pol" aria-label="Permalink to &quot;Opis pól&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Działanie</th><th>Wymagane</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Discord Primary</code>.</td><td>Tak</td></tr><tr><td>Bot Token</td><td>Token bota Discord.</td><td>Tak</td></tr><tr><td>Channel ID</td><td>ID docelowego kanału tekstowego.</td><td>Tak</td></tr><tr><td>Proxy URL (opcjonalnie)</td><td>Używaj tylko, gdy dostęp do Discord CDN jest niestabilny. Wpisz pełny URL z <code>https://</code>.</td><td>Nie</td></tr></tbody></table><h2 id="kroki-konfiguracji" tabindex="-1">Kroki konfiguracji <a class="header-anchor" href="#kroki-konfiguracji" aria-label="Permalink to &quot;Kroki konfiguracji&quot;">​</a></h2><h3 id="_1-utworz-serwer-discord-i-kanał-tekstowy" tabindex="-1">1. Utwórz serwer Discord i kanał tekstowy <a class="header-anchor" href="#_1-utworz-serwer-discord-i-kanał-tekstowy" aria-label="Permalink to &quot;1. Utwórz serwer Discord i kanał tekstowy&quot;">​</a></h3><ol><li>Otwórz Discord.</li><li>Utwórz nowy serwer albo użyj istniejącego serwera, którego jesteś właścicielem.</li><li>Utwórz kanał tekstowy na tym serwerze.</li></ol><p><img src="'+e+'" alt="Utwórz serwer" loading="lazy"></p><h3 id="_2-utworz-bota-w-discord-developer-portal" tabindex="-1">2. Utwórz bota w Discord Developer Portal <a class="header-anchor" href="#_2-utworz-bota-w-discord-developer-portal" aria-label="Permalink to &quot;2. Utwórz bota w Discord Developer Portal&quot;">​</a></h3><ol><li>Otwórz Discord Developer Portal: <code>https://discord.com/developers/applications</code></li><li>Kliknij <code>New Application</code>.</li><li>Wpisz nazwę aplikacji i utwórz ją.</li><li>Otwórz stronę <code>Bot</code> z lewego panelu.</li><li>Wygeneruj lub zresetuj token na stronie <code>Bot</code>.</li><li>Zapisz token.</li></ol><p>Ten token wpisujesz w ImgBed jako <code>Bot Token</code>.</p><p><img src="'+t+'" alt="Zobacz token bota" loading="lazy"></p><h3 id="_3-wygeneruj-link-oauth2-i-zainstaluj-bota" tabindex="-1">3. Wygeneruj link OAuth2 i zainstaluj bota <a class="header-anchor" href="#_3-wygeneruj-link-oauth2-i-zainstaluj-bota" aria-label="Permalink to &quot;3. Wygeneruj link OAuth2 i zainstaluj bota&quot;">​</a></h3><ol><li>Otwórz stronę <code>OAuth2</code> z lewego panelu.</li><li>W sekcji scopes wybierz <code>bot</code>.</li><li>W obszarze uprawnień włącz:</li></ol><table tabindex="0"><thead><tr><th>Uprawnienie</th><th>Wymagane</th></tr></thead><tbody><tr><td>View Channels</td><td>Tak</td></tr><tr><td>Send Messages</td><td>Tak</td></tr><tr><td>Attach Files</td><td>Tak</td></tr><tr><td>Read Message History</td><td>Tak</td></tr></tbody></table><ol start="4"><li>Na dole strony potwierdź, że typ integracji to <code>Guild Install</code>.</li><li>Skopiuj wygenerowany URL.</li><li>Otwórz go w przeglądarce.</li><li>Wybierz serwer docelowy.</li><li>Dokończ autoryzację.</li></ol><p><img src="'+o+'" alt="Wybór uprawnień bota w OAuth2" loading="lazy"></p><p><img src="'+i+'" alt="Zaproszenie bota do kanału" loading="lazy"></p><h3 id="_4-włacz-tryb-deweloperski-i-skopiuj-channel-id" tabindex="-1">4. Włącz tryb deweloperski i skopiuj Channel ID <a class="header-anchor" href="#_4-włacz-tryb-deweloperski-i-skopiuj-channel-id" aria-label="Permalink to &quot;4. Włącz tryb deweloperski i skopiuj Channel ID&quot;">​</a></h3><ol><li>Kliknij ikonę koła zębatego obok swojego avatara w lewym dolnym rogu.</li><li>Otwórz Advanced z lewego panelu.</li><li>Włącz Developer Mode.</li><li>Wróć do docelowego kanału tekstowego.</li><li>Kliknij prawym przyciskiem nazwę kanału.</li><li>Kliknij Copy Channel ID.</li></ol><p>Skopiowany numer to <code>Channel ID</code> wymagany przez ImgBed.</p><p><img src="'+r+'" alt="Włącz tryb deweloperski" loading="lazy"></p><p><img src="'+d+'" alt="Kopiowanie Channel ID" loading="lazy"></p><h3 id="_5-wypełnij-kanał-discord-w-imgbed" tabindex="-1">5. Wypełnij kanał Discord w ImgBed <a class="header-anchor" href="#_5-wypełnij-kanał-discord-w-imgbed" aria-label="Permalink to &quot;5. Wypełnij kanał Discord w ImgBed&quot;">​</a></h3><p>Wróć do okna konfiguracji i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Wartość</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Własna nazwa kanału, np. <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Token zapisany ze strony <code>Bot</code> w Discord Developer Portal.</td></tr><tr><td>Channel ID</td><td>Channel ID skopiowany z Discord.</td></tr><tr><td>Proxy URL (opcjonalnie)</td><td>Tylko gdy potrzeba, np. <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>Po zakończeniu kliknij Zapisz.</p><p><img src="'+n+`" alt="Dodanie konfiguracji Discord" loading="lazy"></p><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak sprawdzić</th></tr></thead><tbody><tr><td>Karta kanału jest widoczna</td><td>Po zapisaniu w Ustawieniach przesyłania powinna pojawić się karta Discord.</td></tr><tr><td>Kanał można włączyć</td><td>Przełącznik Aktywny pozostaje włączony.</td></tr><tr><td>Konfiguracja jest zapisana</td><td>Widok szczegółów pokazuje zapisany Bot Token i Channel ID.</td></tr><tr><td>Upload działa</td><td>Prześlij obraz testowy i sprawdź, czy pojawił się w docelowym kanale tekstowym Discord.</td></tr></tbody></table><h2 id="szybka-lista" tabindex="-1">Szybka lista <a class="header-anchor" href="#szybka-lista" aria-label="Permalink to &quot;Szybka lista&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utwórz serwer Discord</span></span>
<span class="line"><span>-&gt; Utwórz kanał tekstowy</span></span>
<span class="line"><span>-&gt; Utwórz bota w Discord Developer Portal</span></span>
<span class="line"><span>-&gt; Zapisz Bot Token ze strony Bot</span></span>
<span class="line"><span>-&gt; W OAuth2 wybierz bot, View Channels, Send Messages, Attach Files i Read Message History</span></span>
<span class="line"><span>-&gt; Skopiuj wygenerowany URL i autoryzuj bota na serwerze docelowym</span></span>
<span class="line"><span>-&gt; Upewnij się, że docelowy kanał tekstowy ma te same uprawnienia</span></span>
<span class="line"><span>-&gt; Włącz Developer Mode</span></span>
<span class="line"><span>-&gt; Kliknij prawym przyciskiem kanał tekstowy i skopiuj Channel ID</span></span>
<span class="line"><span>-&gt; Wpisz Bot Token i Channel ID w ImgBed</span></span>
<span class="line"><span>-&gt; Zapisz i prześlij obraz testowy</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const D=s(k,[["render",w]]);export{j as __pageData,D as default};
